			var apiRateLimitExceeded = false;
			do {
				const response = this.request.post('https://' + params['api_host'] + apiPath + apiParams, body);

				try {
					if (JSON.parse(response)['code'] === 'TooManyRequests') {

						apiRateLimitExceeded = true;
						Zabbix.sleep(1000);
					} else {
